    opts->ast = 1;
    break;

case 'c':
    opts->interactive = 0;

    if (++i < argc) {
        opts->command.start = (u_char *) argv[i];
        opts->command.length = njs_strlen(argv[i]);
        goto done;
    }

    njs_stderror("option \"-c\" requires argument\n");
    return NJS_ERROR;

case 'd':
    opts->disassemble = 1;
    break;

case 'e':
    if (++i < argc) {
        opts->exit_code = atoi(argv[i]);
        break;
    }

    njs_stderror("option \"-e\" requires argument\n");
    return NJS_ERROR;

case 'f':
    opts->denormals = 0;
